from urllib3.connection import HTTPConnection
from urllib3.connectionpool import HTTPConnectionPool

class UnixSocketConnection(HTTPConnection):
    """Handler untuk koneksi UNIX Socket."""
    def __init__(self, socket_path, timeout=60):
        super().__init__('localhost', timeout=timeout)
        self.socket_path = socket_path

    def connect(self):
        sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
        sock.settimeout(self.timeout)
        sock.connect(self.socket_path)
        self.sock = sock

class UnixSocketAdapter(HTTPAdapter):
    """Adapter requests untuk UNIX Socket."""
    def __init__(self, socket_path):
        self.socket_path = socket_path
        super().__init__()

    def create_connection(self, connector, request, **kwargs):
        return UnixSocketConnection(self.socket_path, timeout=request.timeout)

    def poolmanager(self):
        raise NotImplementedError("Gunakan poolmanager khusus untuk socket.")

    def get_pool(self, request, **kwargs):
        # Implementasi sederhana untuk single socket
        return None 

    def send(self, request, **kwargs):
        # Override untuk menggunakan socket langsung
        import socket
        sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
        sock.settimeout(60)
        try:
            sock.connect(self.socket_path)
            # Format HTTP Request manual untuk socket
            request_bytes = f"{request.method} {request.path_url} HTTP/1.1\r\nHost: localhost\r\nContent-Length: {len(request.body or b'')}\r\n\r\n".encode()
            if request.body:
                request_bytes += request.body
            sock.sendall(request_bytes)

            # Parse response sederhana (produksi butuh parser HTTP lengkap)
            response_data = b""
            while True:
                chunk = sock.recv(4096)
                if not chunk:
                    break
                response_data += chunk
                if b"\r\n\r\n" in response_data:
                    # Header selesai, cek Content-Length untuk body
                    header_part, body_part = response_data.split(b"\r\n\r\n", 1)
                    content_length = 0
                    for line in header_part.split(b"\r\n"):
                        if line.lower().startswith(b"content-length:"):
