# Implementasi Produksi Menggunakan requests-unixsocket pattern (Lebih Stabil)
# Disarankan install: pip install requests
# Untuk UNIX socket, kita manipulasi session mount.

import requests
from requests.adapters import HTTPAdapter
from urllib3.poolmanager import PoolManager
import socket

class UnixHTTPConnectionPool(HTTPConnectionPool):
    def __init__(self, socket_path, timeout=60):
        super().__init__('localhost', timeout=timeout)
        self.socket_path = socket_path

    def _new_conn(self):
        sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
        sock.settimeout(self.timeout)
        sock.connect(self.socket_path)
        return sock

class UnixHTTPAdapter(HTTPAdapter):
    def __init__(self, socket_path, timeout=60):
        self.socket_path = socket_path
        self.timeout = timeout
        super().__init__()

    def init_poolmanager(self, connections, maxsize, block=False):
        self.poolmanager = PoolManager(
            num_pools=connections,
            maxsize=maxsize,
            block=block,
            pool_class=UnixHTTPConnectionPool,
            pool_kwargs={'socket_path': self.socket_path, 'timeout': self.timeout}
        )

class DockerClient:
    def __init__(self, socket_path='/var/run/docker.sock'):
        self.base_url = 'http+unix://localhost'
        self.session = requests.Session()
        self.adapter = UnixHTTPAdapter(socket_path=socket_path)
        self.session.mount('http+unix://', self.adapter)
        self.socket_path = socket_path

    def _request(self, method, endpoint, **kwargs):
        url = f"{self.base_url}{endpoint}"
        try:
            response = self.session.request(method, url, **kwargs)
            response.raise_for_status()
            return response.json() if response.content else None
        except requests.exceptions.RequestException as e:
            raise Exception(f"Docker API Error: {str(e)}")

    def get_containers(self, all=False):
        params = {'all': 'true' if all else 'false'}
        return self._request('GET', '/containers/json', params=params)

    def inspect_container(self, container_id):
        return self._request('GET', f'/containers/{container_id}/json')

    def start_container(self, container_id):
        return self._request('POST', f'/containers/{container_id}/start')

    def stop_container(self, container_id, timeout=10):
        params = {'t': timeout}
        return self._request('POST', f'/containers/{container_id}/stop', params=params)

    def get_logs(self, container_id, stdout=True, stderr=True, tail='all'):
        params = {'stdout': 'true' if stdout else 'false', 'stderr': 'true' if stderr else 'false', 'tail': tail}
        # Logs return text/stream, bukan JSON
        response = self.session.get(f"{self.base_url}/containers/{container_id}/logs", params=params)
        response.raise_for_status()
        return response.content

if __name__ == "__main__":
    # Contoh Usage
    client = DockerClient()
    try:
        containers = client.get_containers(all=True)
        print(f"Total Container: {len(containers)}")
        for c in containers:
            print(f"- {c['Names'][0]} ({c['State']})")
    except Exception as e:
        print(f"Error: {e}")
```

### Catatan Keamanan Kritis (Wajib Dibaca)

1.  **Izin Socket (`/var/run/docker.sock`)**:
    *   File ini setara dengan akses **root**. Siapa pun yang bisa membaca/menulis ke socket ini dapat mengambil alih host.
    *   Pastikan permission `660` dan owner `root:docker`.
    *   Jangan pernah memberikan akses socket ini ke user sembarangan atau container yang tidak terpercaya.

2.  **Ekspos Jaringan**:
    *   **JANGAN** pernah membuka Docker API via TCP (port 2375) tanpa TLS. Ini adalah celah keamanan fatal yang sering dieksploitasi untuk cryptominer atau ransomware.
    *   Jika butuh akses remote, gunakan SSH Tunnel atau konfigurasi Docker Daemon dengan TLS mutual authentication (port 2376).

3.  **Validasi Input**:
    *   Pastikan `container_id` divalidasi sebelum dikirim ke API untuk mencegah injeksi path atau manipulasi request.

4.  **Prinsip Least Privilege**:
    *   Jalankan script ini dengan user yang hanya memiliki akses grup `docker`, bukan root langsung jika memungkinkan.

Gunakan modul ini dengan tanggung jawab. Keamanan server adalah prioritas utama di PT Sherif Network.
